Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: inject a fake handler to control HTTP responses
    private static (DataFetcher fetcher, MockHandler handler) CreateSut()
    {
        var handler = new MockHandler();
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var (fetcher, handler) = CreateSut();
        handler.Response = new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.OK,
            Content = new StringContent("hello")
        };

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpFailure()
    {
        var (fetcher, handler) = CreateSut();
        handler.Response = new HttpResponseMessage(System.Net.HttpStatusCode.InternalServerError);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Cancellation: already-cancelled token ---
    [TestMethod]
    public async Task FetchAsync_Throws_WhenAlreadyCancelled()
    {
        var (fetcher, _) = CreateSut();
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Cancellation: cancelled mid-flight ---
    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledDuringRequest()
    {
        using var cts = new CancellationTokenSource();
        var handler = new MockHandler
        {
            OnSend = _ => cts.Cancel() // cancel while "in-flight"
        };
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Timeout via CancellationTokenSource.CancelAfter ---
    [TestMethod]
    public async Task FetchAsync_Throws_OnTimeout()
    {
        var handler = new MockHandler
        {
            Delay = TimeSpan.FromSeconds(10) // simulate slow server
        };
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Minimal fake handler ---
    private class MockHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(System.Net.HttpStatusCode.OK);
        public TimeSpan Delay { get; set; } = TimeSpan.Zero;
        public Action<HttpRequestMessage>? OnSend { get; set; }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            OnSend?.Invoke(request);
            cancellationToken.ThrowIfCancellationRequested();
            if (Delay > TimeSpan.Zero)
                await Task.Delay(Delay, cancellationToken);
            return Response;
        }
    }
}
```

**Key takeaways:**

- **No real HTTP calls** — `MockHandler` subclasses `HttpMessageHandler`, giving you full control.
- **Cancellation** — test both pre-cancelled tokens and mid-flight cancellation via the `OnSend` callback.
- **Timeouts** — use `CancellationTokenSource(TimeSpan)` paired with a simulated `Delay`; don't rely on `HttpClient.Timeout` in tests.
- **MSTest async** — just return `async Task`; the framework handles awaiting and surfacing exceptions. No need for `[Timeout]` attributes on these fast tests.
